      "keystrokes": "cat > /tmp/probe.c <<'EOF'
#include <stdio.h>
#include <math.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
int main(){
  int fd=open("/app/gpt2-124M.ckpt",O_RDONLY);
  struct stat st; fstat(fd,&st);
  float *W=(float*)mmap(0,st.st_size,PROT_READ,MAP_PRIVATE,fd,0);
  long total=st.st_size/4, o=0;
  printf("total %ld\n",total);
  printf("wte %ld %f %f\n",o,W[o],W[o+50257*768-1]); o+=50257L*768;
  printf("wpe %ld %f %f\n",o,W[o],W[o+1024*768-1]); o+=1024L*768;
  long blk=2*768+768*2304+2304+768*768+768+2*768+768*3072+3072+3072*768+768;
  printf("blk %ld\n",blk);
  for(int h=0;h<12;h++){
    printf("h%d ln1 %ld g=%f b=%f\n",h,o,W[o],W[o+768]); o+=2*768;
    printf("h%d caw %ld cab %ld cpw %ld cpb %ld\n",h,o,o+768*2304,o+768*2304+2304,o+768*2304+2304+768*768);
    o+=768*2304+2304+768*768+768;
    printf("h%d ln2 %ld g=%f b=%f\n",h,o,W[o],W[o+768]); o+=2*768;
    printf("h%d fcw %ld fcb %ld pw %ld pb %ld\n",h,o,o+768*3072,o+768*3072+3072,o+768*3072+3072+3072*768);
    o+=768*3072+3072+3072*768+768;
  }
  printf("lnf %ld g=%f b=%f end %ld diff %ld\n",o,W[o],W[o+768],o+2*768,total-(o+2*768));
  for(int r=0;r<5;r++){
    float nr=0; for(int i=0;i<768;i++){float v=W[(long)r*768+i]; nr+=v*v;}
    printf("row %d norm %f\n",r,sqrtf(nr));
  }
  return 0;
}
EOF
